sys_script.script:
(function executeRule(current, previous) {
    var donorId = current.getValue('donor');
    if (!donorId) return;

    var donor = new GlideRecord('x_1920732_lifeli_0_donor_profile');
    if (donor.get(donorId)) {
        // Update last donation date
        var donationDate = current.getValue('donation_date');
        donor.setValue('last_donation_date', donationDate);

        // Calculate next eligible date using system property
        var days = parseInt(gs.getProperty('x_1920732_lifeli_0.donor_eligibility_days', '90'));
        var nextDate = new GlideDateTime(donationDate);
        nextDate.addDaysUTC(days);
        donor.setValue('next_eligible_date', nextDate.getValue());

        // Set eligibility status to temporarily ineligible
        donor.setValue('eligibility_status', 'temporarily_ineligible');

        donor.update();
    }
})(current, previous);
